-melee">Melee</a></td><td>(ST+CO)/2</td><td align="center">2</td><td align="center">1</td><td align="center">5</td><td>all close combat, armed and unarmed; LTF per style/weapon</td></tr><tr><td><a href="#skill-firearms">Firearms</a></td><td>(CO+PC)/2</td><td align="center">2</td><td align="center">1</td><td align="center">3</td><td>guns and crossbows; LTF per weapon class</td></tr><tr><td><a href="#skill-archery">Archery</a></td><td>(CO+PC)/2</td><td align="center">1</td><td align="center">1</td><td align="center">5</td><td>bows (slings are Athletics)</td></tr><tr><td><a href="#skill-heavy-weapons">Heavy Weapons</a></td><td>(CO+PC)/2</td><td align="center">1</td><td align="center">1</td><td align="center">5</td><td>crew-served weapons, launchers, explosives</td></tr><tr><td><a href="#skill-theory">Theory</a></td><td>IN/2</td><td align="center">2</td><td align="center">1.5</td><td align="center">5</td><td>reasoning and all science, via Fields of Knowledge</td></tr><tr><td><a href="#skill-repair">Repair</a></td><td>(CO+IN)/2</td><td align="center">2</td><td align="center">1</td><td align="center">5</td><td>all technical &amp; assembly work — surgery, watchmaking, electronics, mechanics — via Fields</td></tr><tr><td><a href="#skill-charm">Charm</a></td><td>(AP+PC)/2</td><td align="center">2</td><td align="center">1</td><td align="center">5</td><td>likeability, persuasion, seduction, leadership, first impressions (the old Charisma)</td></tr><tr><td><a href="#skill-confidence">Confidence</a></td><td>(AP+WP)/2</td><td align="center">2</td><td align="center">1</td><td align="center">5</td><td>composure, persuading, bluffing, lying convincingly, intimidation, disguise</td></tr><tr><td><a href="#skill-perform">Perform</a></td><td>(PC+AP)/2</td><td align="center">1</td><td align="center">1</td><td align="center">5</td><td>music, acting, oratory, the expressive arts (craft art = Repair + a Field)</td></tr><tr><td><a href="#skill-cars">Cars</a></td><td>(CO+PC)/2</td><td align="center">1</td><td align="center">1</td><td align="center">5</td><td>driving cars; LTF per model</td></tr><tr><td><a href="#skill-bikes">Bikes</a></td><td>(CO+PC)/2</td><td align="center">1</td><td align="center">1</td><td align="center">5</td><td>motorcycles and bicycles</td></tr><tr><td><a href="#skill-boats">Boats</a></td><td>(CO+PC)/2</td><td align="center">1</td><td align="center">1</td><td align="center">5</td><td>watercraft, sail and powered</td></tr><tr><td><a href="#skill-aircraft">Aircraft</a></td><td>(CO+PC)/2</td><td align="center">1</td><td align="center">1</td><td align="center">5</td><td>fixed-wing and rotary aircraft</td></tr><tr><td><a href="#skill-spacecraft">Spacecraft</a></td><td>(CO+PC)/2</td><td align="center">1</td><td align="center">1</td><td align="center">5</td><td>spacecraft (just vehicles)</td></tr><tr><td><a href="#skill-riding">Riding</a></td><td>(CO+PC)/2</td><td align="center">1</td><td align="center">1</td><td align="center">5</td><td>animal mounts</td></tr></tbody></table><div class="ev-cards"><section class="ev-card" id="skill-search"><h3>Search</h3><dl class="ev-fields"><dt>Formula</dt><dd>(IN+PC)/2</dd><dt>Attributes</dt><dd>IN, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">finding the hidden (everyone has it)</p></section><section class="ev-card" id="skill-initiative"><h3>Initiative</h3><dl class="ev-fields"><dt>Formula</dt><dd>(IN+PC)/2</dd><dt>Attributes</dt><dd>IN, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">acting decisively under pressure (everyone has it)</p></section><section class="ev-card" id="skill-athletics"><h3>Athletics</h3><dl class="ev-fields"><dt>Formula</dt><dd>(ST+CO)/2</dd><dt>Attributes</dt><dd>ST, CO</dd><dt>Cost</dt><dd>2</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">climbing, jumping, running, swimming, throwing (incl. slings), acrobatics, dance</p></section><section class="ev-card" id="skill-stealth"><h3>Stealth</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+PC)/2</dd><dt>Attributes</dt><dd>CO, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">hiding, moving silently, tailing</p></section><section class="ev-card" id="skill-sleight-of-hand"><h3>Sleight of Hand</h3><dl class="ev-fields"><dt>Formula</dt><dd>CO/2</dd><dt>Attributes</dt><dd>CO</dd><dt>Cost</dt><dd>2</dd><dt>Limit</dt><dd>1.5</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">palming, pickpocketing, prestidigitation, concealment</p></section><section class="ev-card" id="skill-melee"><h3>Melee</h3><dl class="ev-fields"><dt>Formula</dt><dd>(ST+CO)/2</dd><dt>Attributes</dt><dd>ST, CO</dd><dt>Cost</dt><dd>2</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">all close combat, armed and unarmed; LTF per style/weapon</p></section><section class="ev-card" id="skill-firearms"><h3>Firearms</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+PC)/2</dd><dt>Attributes</dt><dd>CO, PC</dd><dt>Cost</dt><dd>2</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>3</dd><dt>Tags</dt><dd>modern, sf</dd></dl><p class="ev-body">guns and crossbows; LTF per weapon class</p></section><section class="ev-card" id="skill-archery"><h3>Archery</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+PC)/2</dd><dt>Attributes</dt><dd>CO, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>ancient, fantasy</dd></dl><p class="ev-body">bows (slings are Athletics)</p></section><section class="ev-card" id="skill-heavy-weapons"><h3>Heavy Weapons</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+PC)/2</dd><dt>Attributes</dt><dd>CO, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>modern, sf</dd></dl><p class="ev-body">crew-served weapons, launchers, explosives</p></section><section class="ev-card" id="skill-theory"><h3>Theory</h3><dl class="ev-fields"><dt>Formula</dt><dd>IN/2</dd><dt>Attributes</dt><dd>IN</dd><dt>Cost</dt><dd>2</dd><dt>Limit</dt><dd>1.5</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">reasoning and all science, via Fields of Knowledge</p></section><section class="ev-card" id="skill-repair"><h3>Repair</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+IN)/2</dd><dt>Attributes</dt><dd>CO, IN</dd><dt>Cost</dt><dd>2</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">all technical &amp; assembly work — surgery, watchmaking, electronics, mechanics — via Fields</p></section><section class="ev-card" id="skill-charm"><h3>Charm</h3><dl class="ev-fields"><dt>Formula</dt><dd>(AP+PC)/2</dd><dt>Attributes</dt><dd>AP, PC</dd><dt>Cost</dt><dd>2</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">likeability, persuasion, seduction, leadership, first impressions (the old Charisma)</p></section><section class="ev-card" id="skill-confidence"><h3>Confidence</h3><dl class="ev-fields"><dt>Formula</dt><dd>(AP+WP)/2</dd><dt>Attributes</dt><dd>AP, WP</dd><dt>Cost</dt><dd>2</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">composure, persuading, bluffing, lying convincingly, intimidation, disguise</p></section><section class="ev-card" id="skill-perform"><h3>Perform</h3><dl class="ev-fields"><dt>Formula</dt><dd>(PC+AP)/2</dd><dt>Attributes</dt><dd>PC, AP</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">music, acting, oratory, the expressive arts (craft art = Repair + a Field)</p></section><section class="ev-card" id="skill-cars"><h3>Cars</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+PC)/2</dd><dt>Attributes</dt><dd>CO, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>modern</dd></dl><p class="ev-body">driving cars; LTF per model</p></section><section class="ev-card" id="skill-bikes"><h3>Bikes</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+PC)/2</dd><dt>Attributes</dt><dd>CO, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>modern</dd></dl><p class="ev-body">motorcycles and bicycles</p></section><section class="ev-card" id="skill-boats"><h3>Boats</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+PC)/2</dd><dt>Attributes</dt><dd>CO, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>standard</dd></dl><p class="ev-body">watercraft, sail and powered</p></section><section class="ev-card" id="skill-aircraft"><h3>Aircraft</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+PC)/2</dd><dt>Attributes</dt><dd>CO, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>modern, sf</dd></dl><p class="ev-body">fixed-wing and rotary aircraft</p></section><section class="ev-card" id="skill-spacecraft"><h3>Spacecraft</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+PC)/2</dd><dt>Attributes</dt><dd>CO, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>sf</dd></dl><p class="ev-body">spacecraft (just vehicles)</p></section><section class="ev-card" id="skill-riding"><h3>Riding</h3><dl class="ev-fields"><dt>Formula</dt><dd>(CO+PC)/2</dd><dt>Attributes</dt><dd>CO, PC</dd><dt>Cost</dt><dd>1</dd><dt>Limit</dt><dd>1</dd><dt>BEF</dt><dd>5</dd><dt>Tags</dt><dd>ancient, fantasy</dd></dl><p class="ev-body">animal mounts</p></section></div></div></foresight-table>
